import{_ as r,o as l,c as a,ag as t}from"./chunks/framework.ClpDZR9J.js";const _=JSON.parse('{"title":"新前端技术面试题","description":"","frontmatter":{},"headers":[],"relativePath":"frontend/new-tech/index.md","filePath":"frontend/new-tech/index.md","lastUpdated":1773364959000}'),o={name:"frontend/new-tech/index.md"};function i(n,e,b,s,h,d){return l(),a("div",null,[...e[0]||(e[0]=[t('<h1 id="新前端技术面试题" tabindex="-1">新前端技术面试题 <a class="header-anchor" href="#新前端技术面试题" aria-label="Permalink to &quot;新前端技术面试题&quot;">​</a></h1><p>新前端技术相关面试题整理，涵盖WebAssembly、WebGPU、WebRTC、Web Audio API、Web Speech API、Web Bluetooth、Web USB、Web Serial、WebXR、PWA &amp; Service Worker等新兴技术。</p><h2 id="模块导航" tabindex="-1">模块导航 <a class="header-anchor" href="#模块导航" aria-label="Permalink to &quot;模块导航&quot;">​</a></h2><ul><li>WebAssembly - WebAssembly基础、使用场景、性能优化</li><li>WebGPU - WebGPU基础、图形渲染、计算着色器</li><li>WebRTC - 实时通信、音视频通话、数据传输</li><li>Web Audio API - 音频处理、音频分析、音频合成</li><li>Web Speech API - 语音识别、语音合成</li><li>Web Bluetooth - 蓝牙设备连接、设备通信</li><li>Web USB - USB设备连接、设备通信</li><li>Web Serial - 串口通信、设备连接</li><li>WebXR - 虚拟现实、增强现实、沉浸式体验</li><li>PWA &amp; Service Worker - 渐进式Web应用、离线缓存、推送通知</li></ul><h2 id="学习建议" tabindex="-1">学习建议 <a class="header-anchor" href="#学习建议" aria-label="Permalink to &quot;学习建议&quot;">​</a></h2><ol><li><strong>理解技术原理</strong>: 理解各种新前端技术的基本原理和设计思想</li><li><strong>掌握核心API</strong>: 掌握各种技术的核心API和使用方法</li><li><strong>实践项目</strong>: 通过实践项目加深对新技术的理解</li><li><strong>关注兼容性</strong>: 关注浏览器兼容性和polyfill方案</li><li><strong>性能优化</strong>: 学习如何优化新技术的性能和用户体验</li></ol><h2 id="参考资源" tabindex="-1">参考资源 <a class="header-anchor" href="#参考资源" aria-label="Permalink to &quot;参考资源&quot;">​</a></h2><ul><li><a href="https://webassembly.org/" target="_blank" rel="noreferrer">WebAssembly官方文档</a></li><li><a href="https://www.w3.org/TR/webgpu/" target="_blank" rel="noreferrer">WebGPU官方文档</a></li><li><a href="https://webrtc.org/" target="_blank" rel="noreferrer">WebRTC官方文档</a></li><li><a href="https://developer.mozilla.org/zh-CN/docs/Web/API/Web_Audio_API" target="_blank" rel="noreferrer">Web Audio API文档</a></li><li><a href="https://developer.mozilla.org/zh-CN/docs/Web/API/Web_Speech_API" target="_blank" rel="noreferrer">Web Speech API文档</a></li><li><a href="https://developer.mozilla.org/zh-CN/docs/Web/API/Web_Bluetooth_API" target="_blank" rel="noreferrer">Web Bluetooth API文档</a></li><li><a href="https://developer.mozilla.org/zh-CN/docs/Web/API/WebUSB_API" target="_blank" rel="noreferrer">Web USB API文档</a></li><li><a href="https://developer.mozilla.org/zh-CN/docs/Web/API/Web_Serial_API" target="_blank" rel="noreferrer">Web Serial API文档</a></li><li><a href="https://developer.mozilla.org/zh-CN/docs/Web/API/WebXR_Device_API" target="_blank" rel="noreferrer">WebXR API文档</a></li><li><a href="https://web.dev/progressive-web-apps/" target="_blank" rel="noreferrer">PWA官方文档</a></li></ul>',8)])])}const p=r(o,[["render",i]]);export{_ as __pageData,p as default};
